@Override
  public Map<String, Object> toRaw() {
    Map<String, Object> map = super.toRaw();
    mapPutSafe(map, PRODUCT_ID, productId);
    if (categoryId != null) {
      mapPutSafe(map, CATEGORY_ID, categoryId);
    }
    mapPutSafe(map, BV_PRODUCT_TYPE, bvProductType.toString());
    return map;
  }
